reduced_function_code.sanitize_cookie_path:
static char *sanitize_cookie_path(const char *cookie_path)
{
size_t len;
char *new_path = strdup(cookie_path);

if(!new_path)
    return NULL;
len = strlen(new_path);
if(new_path[0] == '\"') {
    memmove((void *)new_path, (const void *)(new_path + 1), len);
    len--;
  }
if(len && (new_path[len - 1] == '\"')) {
    new_path[len - 1] = 0x0;
    len--;
  }
if(new_path[0] != '/') {
    /* Let cookie-path be the default-path. */
    free(new_path);
    new_path = strdup("/");
    return new_path;
  }
if(len && new_path[len - 1] == '/') {
    new_path[len - 1] = 0x0;
  }
return new_path;
}

